{
  "schemaVersion": 2,
  "id": "reading-comfort-pack",
  "name": "Reading Comfort Pack",
  "version": "1.0.0",
  "entry": null,
  "pluginType": "theme-pack",
  "capabilities": ["theme.style", "theme.snippet", "theme.token"],
  "platforms": ["desktop", "web"],
  "requiresRestart": false,
  "experimental": false,
  "minAppVersion": "0.6.0",
  "maxAppVersion": null,
  "permissions": {
    "theme": {
      "register": true
    }
  },
  "contributes": {
    "theme": {
      "style": [
        {
          "file": "theme/style/reading-pack-accent.css",
          "label": "Reading Pack Accent",
          "description": "Literary cream palette with restrained heading accents."
        }
      ],
      "snippets": [
        {
          "file": "theme/snippets/reading-focus.css",
          "id": "reading-focus",
          "label": "Reading Focus",
          "description": "Slightly wider column and calmer selection tint for long-form reading.",
          "defaultEnabled": true
        }
      ],
      "tokens": [
        {
          "file": "theme/tokens/reading-pack.json",
          "label": "Reading Pack Tokens",
          "description": "JSON palette preset paired with Reading Pack Accent CSS."
        }
      ],
      "defaultEnable": {
        "style": false,
        "snippets": ["reading-focus"]
      }
    },
    "commands": [],
    "preferencesSections": [],
    "panels": []
  }
}

/**
 * reading-focus — plugin-bundled UI snippet
 *
 * Copy target: ~/.luna/theme/snippets/reading-focus.css
 * Stacks on active palette; enable one reading overlay snippet at a time.
 */

html[data-theme='light'],
html[data-theme='dark'] {
  --editor-column-width: 74ch;
  --reading-focus-selection: color-mix(in srgb, var(--accent) 14%, transparent);
}

.preview-pane.markdown-visual-editor .ProseMirror {
  line-height: 1.75;
}

.preview-pane.markdown-visual-editor .ProseMirror ::selection {
  background: var(--reading-focus-selection);
}

.preview-pane.markdown-visual-editor .pm-paragraph-block + .pm-paragraph-block {
  margin-top: 0.85em;
}

/**
 * Reading Pack Accent — plugin-bundled external CSS theme
 *
 * Pair with theme/tokens/reading-pack.json or use standalone.
 * Copy target: ~/.luna/theme/style/reading-pack-accent.css
 */

html[data-theme='light'] {
  --surface-app: #f7f2e8;
  --surface-panel: rgba(255, 252, 246, 0.94);
  --surface-editor: #fffdf8;
  --surface-preview: #faf6ee;
  --surface-hover: rgba(139, 94, 60, 0.08);
  --surface-elevated: #fffdf8;
  --text-primary: #2a241c;
  --text-secondary: #5c5246;
  --text-muted: #7a6f62;
  --text-tertiary: #7a6f62;
  --border-subtle: rgba(42, 36, 28, 0.12);
  --border-strong: rgba(42, 36, 28, 0.18);
  --accent: #8b5e3c;
  --link: #7a4f2f;
  --link-hover: #6a4328;
  --link-visited: #6b4a7a;
  --focus-ring: rgba(139, 94, 60, 0.22);
  --code-bg: #f3ede2;
  --code-gutter-fg: #7a6f62;
  --code-gutter-bg: #ebe3d4;
  --inline-code-bg: #efe6d8;
  --shadow-soft: 0 1px 2px rgba(42, 36, 28, 0.06);
  --shadow-panel: 0 10px 28px rgba(42, 36, 28, 0.1);
  --editor-column-width: 72ch;
}

html[data-theme='dark'] {
  --surface-app: #1a1713;
  --surface-panel: rgba(34, 30, 26, 0.94);
  --surface-editor: #221e1a;
  --surface-preview: #171411;
  --surface-hover: rgba(212, 181, 141, 0.1);
  --surface-elevated: #2a241f;
  --text-primary: #f2e8da;
  --text-secondary: #c9bba8;
  --text-muted: #9f907d;
  --text-tertiary: #9f907d;
  --border-subtle: rgba(242, 232, 218, 0.1);
  --border-strong: rgba(242, 232, 218, 0.16);
  --accent: #d4b58d;
  --link: #e0c39a;
  --link-hover: #edd1ab;
  --link-visited: #c9a8e8;
  --focus-ring: rgba(212, 181, 141, 0.24);
  --code-bg: #2a241f;
  --code-gutter-fg: #9f907d;
  --code-gutter-bg: #1f1b17;
  --inline-code-bg: #342e28;
  --shadow-soft: 0 1px 2px rgba(0, 0, 0, 0.45);
  --shadow-panel: 0 12px 36px rgba(0, 0, 0, 0.5);
  --editor-column-width: 72ch;
}

/* Heading accent — NodeView selectors */
.pm-heading-block--l1 .pm-heading-content {
  letter-spacing: -0.02em;
}

.pm-heading-block--l2 .pm-heading-content {
  border-left: 3px solid color-mix(in srgb, var(--accent) 55%, transparent);
  padding-left: 0.65em;
}
